arguments.command:
# Use nm to find nearest symbol for the SGen worker addresses
DBGFILE="/tmp/symbols/libmonosgen-2.0.so.dbg"
# Find symbols near 0x2f4b20 and 0x2f4c84
llvm-nm-18 --defined-only "$DBGFILE" 2>/dev/null | awk '{print $1, $3}' | sort | awk -v a1="2f4b20" -v a2="2f4c84" '
