arguments.command:
SOFILE="/tmp/symbols_mono/libmonosgen-2.0.so"
DBGFILE="/tmp/symbols_mono/libmonosgen-2.0.so.dbg"

# Try using the .so file to look up dynamic symbols for those addresses
echo "=== Dynamic symbols near 0x2f4b20 and 0x2f4c84 ==="
llvm-nm-18 -D "$SOFILE" 2>/dev/null | grep -E '^\w+ [Tt]' | sort | awk '
{
  addr = strtonum("0x" $1)
  name = $3
  if (addr <= 0x2f4b20) { n1 = name; a1 = $1; off1 = 0x2f4b20 - addr }
  if (addr <= 0x2f4c84) { n2 = name; a2 = $1; off2 = 0x2f4c84 - addr }
}
END {
  printf "0x2f4b20 -> %s+0x%x (base: 0x%s)\n", n1, off1, a1
  printf "0x2f4c84 -> %s+0x%x (base: 0x%s)\n", n2, off2, a2
}'

echo ""
echo "=== Also check all symbols (not just T) ==="
